select
  c.id,
  f.id,
  s.id,
  a.data_hora,
  a.status,
  a.valor
from _atend a
left join clientes     c on c.id_externo = a.id_cliente_ext
left join funcionarios f on f.nome        = a.colaborador
left join servicos     s on s.nome like '%' || a.servico || '%';